		// string marshal of arbitrary bytes never fails, but stay safe.
		return nil
	}
	return s
}

// isJSONObjectOrArray reports whether b is valid JSON whose first
// non-whitespace byte is '{' or '['.
func isJSONObjectOrArray(b []byte) bool {
	for _, c := range b {
		switch c {
		case ' ', '\t', '\n', '\r':
			continue
		case '{', '[':
			return json.Valid(b)
		default:
			return false
		}
	}
	return false
}

